<?php class Model_FactorConversion{	private static $_instance;		public static function getInstance()	{		if(null == self::$_instance)		{			self::$_instance = new self;		}		return self::$_instance;	}	private function __construct(){}	public function getFactorConversion($id)	{		return Model_Mapper_FactorConversion::getInstance()->getFactorConversion($id);	}		public function getFactoresDeConversion()	{		return Model_Mapper_FactorConversion::getInstance()->getFactoresDeConversion();	}		public function getIndicadorByFactorConversion($idFactor)	{		return Model_Mapper_FactorConversion::getInstance()->getIndicadorByFactorConversion($idFactor);	}		public function getFactorConversionByIndicador($idIndicador)	{		return Model_Mapper_FactorConversion::getInstance()->getFactorConversionByIndicador($idIndicador);	}		public function getIdFactorConversionByFicha($ficha)	{		return Model_Mapper_FactorConversion::getInstance()->getIdFactorConversionByFicha($ficha);	}		public function updateFactorConversion($fila)	{		return Model_Mapper_FactorConversion::getInstance()->updateFactorConversion($fila);	}		public function insertFactorConversion($fila)	{		return Model_Mapper_FactorConversion::getInstance()->insertFactorConversion($fila);	}}